+	if v2 {
+		gitProtocol = "version=2"
+	}
+	cmd, stderr, err := c.startRPC(ctx, service, gitProtocol)
+	if err != nil {
+		return nil, err
+	}
+	copyErr := make(chan error, 1)
+	go func() {
+		_, err := io.Copy(cmd.Stdin, body)
+		closeErr := cmd.Stdin.Close()
+		if err != nil {
+			copyErr <- err
+			return
+		}
+		copyErr <- closeErr
+	}()
